import com.google.android.gms.location.Priority

@Composable
fun MapScreen(hasLocationPermission: Boolean) {
    val context = LocalContext.current
    val fountains = remember { FountainRepository.loadFountains(context) }

    // Configure osmdroid
    remember {
        Configuration.getInstance().apply {
            userAgentValue = context.packageName
        }
    }

    AndroidView(
        modifier = Modifier.fillMaxSize(),
        factory = { ctx ->
            MapView(ctx).apply {
                val cartoPositron = object : OnlineTileSourceBase(
                    "CartoPositron",
                    0, 20, 256, ".png",
                    arrayOf(
                        "https://a.basemaps.cartocdn.com/light_all/",
                        "https://b.basemaps.cartocdn.com/light_all/",
                        "https://c.basemaps.cartocdn.com/light_all/",
                    ),
                ) {
                    override fun getTileURLString(pMapTileIndex: Long): String {
                        val z = MapTileIndex.getZoom(pMapTileIndex)
                        val x = MapTileIndex.getX(pMapTileIndex)
                        val y = MapTileIndex.getY(pMapTileIndex)
                        return "$baseUrl$z/$x/$y$mImageFilenameEnding"
                    }
                }
                setTileSource(cartoPositron)
                setMultiTouchControls(true)
                controller.setZoom(18.0)
                controller.setCenter(GeoPoint(47.3769, 8.5417)) // Zurich center

                // My location overlay
                if (hasLocationPermission) {
                    val locationOverlay = MyLocationNewOverlay(GpsMyLocationProvider(ctx), this)
                    locationOverlay.enableMyLocation()
